import numpy as np

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    # Factor to inflate the distances of the frequently used edges
    inflation_factor = 1.1

    # Update the number of times each edge is used based on current local optimal tours
    n = edge_distance.shape[0]
    for tour in local_opt_tours:
        for i in range(len(tour)):
            if i == len(tour) - 1:
                from_node, to_node = tour[i], tour[0]
            else:
                from_node, to_node = tour[i], tour[i+1]
            edge_n_used[from_node, to_node] += 1
            edge_n_used[to_node, from_node] += 1

    # Update distances by inflating them based on the usage frequency
    updated_edge_distance = np.copy(edge_distance)
    high_usage_threshold = np.percentile(edge_n_used, 75)  # use 75th percentile as threshold to define high usage
    for i in range(n):
        for j in range(n):
            if edge_n_used[i, j] > high_usage_threshold:
                updated_edge_distance[i, j] *= inflation_factor

    return updated_edge_distance
